480	    private static ToolRegistry buildToolRegistry(AppConfig config) {
481	        String wd = config.getTool().getWorkingDirectory();
482	        int timeout = config.getTool().getTimeoutSeconds();
483	
484	        ToolRegistry registry = new ToolRegistry();
485	        registry.register(new ToolSearchTool(registry));
486	        registry.registerAll(
487	                new ReadFileTool(wd),
488	                new WriteFileTool(wd),
489	                new EditFileTool(wd),
490	                new GlobTool(wd),
491	                new GrepTool(wd),
492	                new ExecuteCommandTool(wd, timeout)
493	        );
494	        return registry;
495	    }
496	
497	    /**
498	     * Initialize MCP connections if configured.
499	     *
500	     * @param config   the application configuration
501	     * @param registry the tool registry to register into
502	     * @param writer   the PrintWriter for output (from TerminalUI)
503	     * @return the McpManager (non-null even if no servers configured — it's a no-op manager)
504	     */
505	    private static McpManager initMcp(AppConfig config, ToolRegistry registry, java.io.PrintWriter writer) {
506	        AppConfig.McpConfigNode mcpConfig = config.getMcp();
507	        if (mcpConfig == null || mcpConfig.getServers() == null || mcpConfig.getServers().isEmpty()) {
508	            return null;
509	        }
510	        McpManager manager = new McpManager(mcpConfig.getServers());
511	        manager.registerAllMcpTools(registry, writer);
512	        return manager;
513	    }
514	
515	    /**
516	     * Gracefully shut down all MCP client connections.
517	     */
518	    private static void shutdownMcp(McpManager manager) {
519	        if (manager != null) {
520	            manager.shutdown();
521	        }
522	    }
523	}
